#### 5.1 User Entity
**File**: `user/UserEntity.kt`

```kotlin
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val nickname: String,
    val gender: String, // M, F, U
    val age: Int,
    var bio: String? = null,
    var avatar: String? = null,

    @Column(nullable = false)
    var mannerScore: Float = 3.5f,

    @Column(nullable = false)
    var verificationStatus: Int = 0, // 0=ACTIVE, 1=INACTIVE, 2=BANNED, 3=SUSPENDED

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

